// ParticleComponent.js
import React from "react";
import Particles from "react-tsparticles";

const ParticlesComponents = () => {
  return (
    <Particles
      id="tsparticles"
      options={{
        fullScreen: { enable: false }, // Set to true if you want particles to cover the whole screen
        background: {
          color: { value: "#000a1c" },
        },
        particles: {
          number: {
            value: 50,
            density: {
              enable: true,
              area: 800,
            },
          },
          color: {
            value: "#ffffff",
          },
          shape: {
            type: "circle",
          },
          opacity: {
            value: 0.5,
            random: false,
          },
          size: {
            value: 3,
            random: true,
          },
          move: {
            enable: true,
            speed: 2,
            direction: "none",
            random: false,
            straight: false,
            outMode: "out",
            attract: { enable: false },
          },
        },
        interactivity: {
          events: {
            onHover: { enable: true, mode: "repulse" },
            onClick: { enable: true, mode: "push" },
          },
          modes: {
            repulse: { distance: 100, duration: 0.4 },
            push: { particles_nb: 4 },
          },
        },
      }}
    />
  );
};

export default ParticlesComponents;
